INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (10046, "2030/12/17 14:59:59", 0.0, 2, "2020/07/31 12:00:00", "アヤネ", 24, 0.0, 0.0, 24001, 102301, "やったね、ぷうきち！\nこれならお兄ちゃんたちの\nお手本になれたよね！", 2, 401);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (10046, "2030/12/17 14:59:59", 2.21, 2, "2020/07/31 12:00:00", "アヤネ", 24, 0.0, 0.0, 24002, 102301, "私たちの勝ちだね！\nぷうきちと一緒なら\nどんなボールでも\nホームランを打ってみせるよ！", 1, 402);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (10046, "2030/12/17 14:59:59", 0.0, 2, "2020/07/31 12:00:00", "アヤネ", 24, 0.0, 0.0, 24003, 102301, "やったやったぁ！\nお兄ちゃん、見ててくれた？\n私、すっごくがんばったよ！", 2, 403);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (10046, "2030/12/17 14:59:59", 1.99, 1, "2020/07/31 12:00:00", "アサヒ", 24, 0.0, 0.0, 24004, 192201, "特訓の成果が出たみたいだ！\nもっと練習を重ねて\nこの調子で上達していこう！", 2, 701);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (10046, "2030/12/17 14:59:59", 2.21, 2, "2020/07/31 12:00:00", "アサヒ", 24, 0.0, 0.0, 24005, 192201, "よし、いい感じだ！\nキャプテンとしての仕事は\nきっちり果たせそうだよ", 1, 702);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (10046, "2030/12/17 14:59:59", 3.33, 1, "2020/07/31 12:00:00", "アサヒ", 24, 0.0, 0.0, 24006, 192201, "試合に向けて\nいい感覚を掴めた気がするよ！\nこのまま一気に全国大会だ！", 2, 703);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (10046, "2030/12/17 14:59:59", 0.0, 2, "2020/07/31 12:00:00", "部員３", 24, 0.0, 0.0, 24007, 192301, "このくらい余裕だ\nオレたちは全国大会を\n目指してるんだからな", 2, 801);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (10046, "2030/12/17 14:59:59", 2.68, 2, "2020/07/31 12:00:00", "部員３", 24, 0.0, 0.0, 24008, 192301, "オレだって\nビーチベースボール選手だ\nどんな球だろうが\n全部スタンドまで飛ばしてやる", 1, 802);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (10046, "2030/12/17 14:59:59", 0.0, 2, "2020/07/31 12:00:00", "部員３", 24, 0.0, 0.0, 24009, 192301, "いい感じだ\nこれなら試合でも活躍できそうだ\n大暴れしてやる！", 2, 803);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (10046, "2030/12/17 14:59:59", 0.0, 1, "2020/07/31 12:00:00", "", 24, 0.0, 0.0, 24010, 192501, "やった！", 1, 501);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (10046, "2030/12/17 14:59:59", 0.0, 1, "2020/07/31 12:00:00", "", 24, 0.0, 0.0, 24011, 192501, "勝ったよ！", 1, 502);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (10046, "2030/12/17 14:59:59", 0.0, 1, "2020/07/31 12:00:00", "", 24, 0.0, 0.0, 24012, 192501, "いい調子！", 1, 503);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (10046, "2030/12/17 14:59:59", 5.33, 2, "2020/07/31 12:00:00", "ミサト", 24, 0.0, 0.0, 24013, 113501, "あら～…もしかして\n勝っちゃったのかしら？\nみんなの練習を見ていたから\nかもしれないわね", 6, 111);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (10046, "2030/12/17 14:59:59", 6.85, 2, "2020/07/31 12:00:00", "ミサト", 24, 0.0, 0.0, 24014, 113501, "みんなの力になりたくて\n先生も頑張ってみました～！\nうまく投げられたみたいで\nよかったわ～！", 1, 112);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (10046, "2030/12/17 14:59:59", 3.0, 2, "2020/07/31 12:00:00", "ミサト", 24, 0.0, 0.0, 24015, 113501, "練習お疲れさま～！\n先生も協力できて\nとってもうれしいわ～♪\n次も頑張りましょうね～！", 1, 113);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (10046, "2030/12/17 14:59:59", 6.11, 2, "2020/07/31 12:00:00", "ダイチ", 24, 0.0, 0.0, 24016, 192401, "まだ練習が足りねえみてえだな\nこれっぽっちも本気で\n投げてねえっつーの\nもう一回やんぞ！", 1, 611);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (10046, "2030/12/17 14:59:59", 6.75, 2, "2020/07/31 12:00:00", "ダイチ", 24, 0.0, 0.0, 24017, 192401, "ふん、当然の結果だな\n俺の球は、誰にも打てねえよ！\nまたやりてえっつーなら\nとことん付き合ってやるぜ！", 1, 612);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (10046, "2030/12/17 14:59:59", 0.0, 2, "2020/07/31 12:00:00", "ダイチ", 24, 0.0, 0.0, 24018, 192401, "おっしゃあ！\nこの勢いで全国に行ってやるぜ！\n全員三振で仕留めてやる！", 2, 613);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (10046, "2030/12/17 14:59:59", 4.52, 1, "2020/07/31 12:00:00", "ハツネ", 24, 0.0, 0.0, 24019, 113401, "きらーん☆\nハツネちゃんの大勝利なのだ～！\nみんながもっと上達できるように\n私もまだまだ頑張るからね！", 2, 211);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (10046, "2030/12/17 14:59:59", 3.89, 1, "2020/07/31 12:00:00", "ハツネ", 24, 0.0, 0.0, 24020, 113401, "やったあ！　私の勝ちだね！\nチアリーダーもピッチャーも\nハツネちゃんに任せてよ！", 2, 212);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (10046, "2030/12/17 14:59:59", 13.49, 2, "2020/07/31 12:00:00", "ハツネ", 24, 0.0, 0.0, 24021, 113401, "よお～し、この調子でもっと\n頑張ろう…と思ったけど\n超能力を使ったから…\n眠くなってきちゃった…すやぁ…", 1, 213);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (10046, "2030/12/17 14:59:59", 3.17, 2, "2020/07/31 12:00:00", "カヤ", 24, 0.0, 0.0, 24022, 106501, "いい勝負だったぜ！\nたぎっちまって\nつい本気で投げちまったよ", 1, 311);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (10046, "2030/12/17 14:59:59", 4.42, 2, "2020/07/31 12:00:00", "カヤ", 24, 0.0, 0.0, 24023, 106501, "どうだ？\nオレ様のボールは熱かっただろ！\nま、でもおまえらの根性も\nなかなかのもんだったぜ", 1, 312);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (10046, "2030/12/17 14:59:59", 2.89, 1, "2020/07/31 12:00:00", "カヤ", 24, 0.0, 0.0, 24024, 106501, "なんだよ、そんなもんか？\nこっちはまだまだ投げたりねえ\nもっと勝負しようぜ！", 6, 313);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (10046, "2030/12/17 14:59:59", 3.71, 3, "2020/07/31 12:00:00", "アヤネ", 24, 0.0, 0.0, 24025, 102301, "あとちょっとだったのに～！\n次こそぷうきちと一緒に\n勝ってみせるからね！", 4, 421);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (10046, "2030/12/17 14:59:59", 5.1, 1, "2020/07/31 12:00:00", "アサヒ", 24, 0.0, 0.0, 24026, 192201, "いい勝負だったね！\nでも、やっぱり悔しいな…\nもっと練習して\n今度は絶対に俺が勝つから！", 2, 721);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (10046, "2030/12/17 14:59:59", 4.34, 3, "2020/07/31 12:00:00", "部員３", 24, 0.0, 0.0, 24027, 192301, "ちっ…あと一歩足りなかったか\n次こそは絶対に勝つから\nそのつもりでいろ", 1, 821);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (10046, "2030/12/17 14:59:59", 0.0, 1, "2020/07/31 12:00:00", "", 24, 0.0, 0.0, 24028, 192501, "いい勝負だったよ\nまたやろうね", 1, 521);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (10046, "2030/12/17 14:59:59", 5.62, 2, "2020/07/31 12:00:00", "ミサト", 24, 0.0, -360.0, 24029, 113501, "とってもよくできました～♪\n頑張ってくれて先生うれしいわ\nこれからも試合に向けて\n練習していきましょうね～", 1, 101);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (10046, "2030/12/17 14:59:59", 9.58, 2, "2020/07/31 12:00:00", "ミサト", 24, 0.0, -360.0, 24030, 113501, "頑張った成果ね～！\nこのまま練習を続ければ\nもっとすごい成績を残せそうよ\n期待してますからね～！", 1, 102);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (10046, "2030/12/17 14:59:59", 0.0, 2, "2020/07/31 12:00:00", "ミサト", 24, 0.0, -360.0, 24031, 113501, "いい子、いい子～♪\n頑張り屋さんのあなたを\nたっくさん褒めてあげますからね", 2, 103);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (10046, "2030/12/17 14:59:59", 9.13, 1, "2020/07/31 12:00:00", "ミサト", 24, 0.0, -360.0, 24032, 113501, "夢に向けて、一歩前進できたわね\nこの調子で、夢を叶えましょう\n目指せ、全国大会～！", 2, 104);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (10046, "2030/12/17 14:59:59", 8.27, 2, "2020/07/31 12:00:00", "ミサト", 24, 0.0, -360.0, 24033, 113501, "絶好調ね～♪\nきっと試合でも大活躍\n間違いなしだわ\n楽しみにしていますからね～！", 1, 105);
